using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpStdioServer;

[McpServerToolType]
public sealed class ApiTools
{
    [McpServerTool, Description("Fetches data from the external API at the given path and returns the JSON response.")]
    public static async Task<string> FetchExternalData(
        IHttpClientFactory httpClientFactory,
        [Description("Relative API path to query, e.g. \"users/42\".")] string path,
        CancellationToken cancellationToken = default)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");

        using var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        using var content = await response.Content.ReadAsStreamAsync(cancellationToken);
        using var doc = await JsonDocument.ParseAsync(content, cancellationToken: cancellationToken);

        return JsonSerializer.Serialize(doc.RootElement, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol;
using ModelContextProtocol.Server;

namespace McpStdioServer;

[McpServerPromptType]
public sealed class SummarizePrompts
{
    [McpServerPrompt, Description("Generates a prompt that asks the model to summarize the provided text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional desired length: short, medium, or long.")] string? length = "medium")
    {
        return
        [
            new(Role.User,
                $"""
                 Summarize the following text. Target a {length} length summary.
                 Preserve key facts and main conclusions.

                 ---
                 {text}
                 ---
                 """)
        ];
    }
}

